    def LATIN_SYMBOL_WITH_LATIN_SUBSCRIPT(self, tokens):
        base, sub = tokens.value.split("_")
        if sub.startswith("{"):
            return sympy.Symbol("%s_{%s}" % (base, sub[1:-1]))
        else:
            return sympy.Symbol("%s_{%s}" % (base, sub))

