    def LATIN_SYMBOL_WITH_GREEK_SUBSCRIPT(self, tokens):
        base, sub = tokens.value.split("_")
        if sub.startswith("{"):
            greek_letter = sub[2:-1]
        else:
            greek_letter = sub[1:]

        greek_letter = re.sub("var", "", greek_letter)
        return sympy.Symbol("%s_{%s}" % (base, greek_letter))


