    def GREEK_SYMBOL_WITH_GREEK_SUBSCRIPT(self, tokens):
        base, sub = tokens.value.split("_")
        greek_base = re.sub("var", "", base[1:])

        if sub.startswith("{"):
            greek_sub = sub[2:-1]
        else:
            greek_sub = sub[1:]

        greek_sub = re.sub("var", "", greek_sub)
        return sympy.Symbol("%s_{%s}" % (greek_base, greek_sub))

