    def multi_letter_symbol(self, tokens):
        if len(tokens) == 4: # no primes (single quotes) on symbol
            return sympy.Symbol(tokens[2])
        if len(tokens) == 5: # there are primes on the symbol
            return sympy.Symbol(tokens[2] + tokens[4])

