    def number(self, tokens):
        if tokens[0].type == "CMD_IMAGINARY_UNIT":
            return sympy.I

        if "." in tokens[0]:
            return sympy.core.numbers.Float(tokens[0])
        else:
            return sympy.core.numbers.Integer(tokens[0])

